import React, { useEffect, useState } from 'react';
import Cultura from './pages/Cultura'; // Esto busca el 'export default'
import { obtenerSitios } from './services/culturaService'; // Esto busca el export nombrado

function App() {
    const [sitios, setSitios] = useState([]);

    useEffect(() => {
        const cargarDatos = async () => {
            const datos = await obtenerSitios();
            setSitios(datos || []);
        };
        cargarDatos();
    }, []);

    return (
        <Cultura sitios={sitios} />
    );
}

export default App;
